## 新增 ViewModifiers

```swift
// Prism/Presentation/DesignSystem/PrismModifiers.swift

struct PrismScreenModifier: ViewModifier {
    func body(content: Content) -> some View {
        content
            .background(PrismColors.background.ignoresSafeArea())
            .preferredColorScheme(.dark)
    }
}

struct PrismToolbarModifier: ViewModifier {
    func body(content: Content) -> some View {
        content
            .background(.ultraThinMaterial.opacity(0.5))
            .frame(height: 44)
    }
}

extension View {
    func prismScreen() -> some View { modifier(PrismScreenModifier()) }
    func prismToolbar() -> some View { modifier(PrismToolbarModifier()) }
}
```

